```class Solution {
public:
    int minimumScore(string s, string t) {
        int n = s.size(), m = t.size();
        int res = m, left = 0, right = m - 1, diff = 0;
        for (int i = 0; i < m; i++) {
            if (s[i] != t[i]) {
                diff++;
                if (i < right) right = i;
            }
        }
        for (int i = m - 1; i >= 0; i--) {
            if (s[i] != t[i]) {
                diff++;
                if (i > left) left = i;
            }
        }
        return min(res - left, right - left + 1);
    }
};```
